const input = $input.first().json;
const action = input.action || 'help';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const FILE_BRIDGE = 'http://file-bridge:3200';
const OFF_BASE = 'https://world.openfoodfacts.org';
const OFF_SEARCH = 'https://search.openfoodfacts.org';
const WGER_BASE = 'https://wger.de/api/v2';
const UA = 'n8n-claw/fitness-buddy/1.0';

const pgHeaders = {
  apikey: SUPABASE_KEY,
  Authorization: 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json',
  Prefer: 'return=representation'
};

async function pg(method, path, body) {
  const opts = {
    method,
    url: SUPABASE_URL + '/rest/v1' + path,
    headers: pgHeaders,
    json: true,
    timeout: 15000
  };
  if (body !== undefined) opts.body = body;
  return await helpers.httpRequest(opts);
}

async function pgPatch(path, body) {
  return await helpers.httpRequest({
    method: 'PATCH',
    url: SUPABASE_URL + '/rest/v1' + path,
    headers: pgHeaders,
    body,
    json: true,
    timeout: 15000
  });
}

async function getOpenAIKey() {
  const r = await pg('GET', '/template_credentials?template_id=eq.fitness-buddy&cred_key=eq.openai_api_key&select=cred_value');
  if (!r || !r[0] || !r[0].cred_value) {
    throw new Error('OpenAI API Key not configured. Use add_credential action on the library_manager to set it up.');
  }
  return r[0].cred_value;
}

async function openaiChat(messages, opts) {
  const apiKey = await getOpenAIKey();
  const body = {
    model: (opts && opts.model) || 'gpt-4o-mini',
    temperature: opts && opts.temperature != null ? opts.temperature : 0.2,
    messages
  };
  if (opts && opts.response_format) body.response_format = opts.response_format;
  if (opts && opts.max_tokens) body.max_tokens = opts.max_tokens;
  return await helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: { Authorization: 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
    body,
    json: true,
    timeout: 90000
  });
}

async function llmJSON(systemPrompt, userPrompt, schema) {
  const resp = await openaiChat([
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ], {
    response_format: { type: 'json_schema', json_schema: { name: 'extracted', strict: true, schema } }
  });
  return JSON.parse(resp.choices[0].message.content);
}

async function fetchFile(fileRef) {
  const meta = await helpers.httpRequest({
    method: 'GET',
    url: FILE_BRIDGE + '/files/' + encodeURIComponent(fileRef),
    json: true,
    timeout: 15000
  });
  const bin = await helpers.httpRequest({
    method: 'GET',
    url: FILE_BRIDGE + '/files/' + encodeURIComponent(fileRef) + '/content?encoding=base64',
    json: true,
    timeout: 30000
  });
  return { mime: (meta && meta.mime_type) || 'image/jpeg', base64: bin && bin.content_base64 };
}

function bmr(sex, weightKg, heightCm, ageYears) {
  const base = 10 * weightKg + 6.25 * heightCm - 5 * ageYears;
  return sex === 'm' ? base + 5 : base - 161;
}

const ACTIVITY_MULT = { sedentary: 1.2, light: 1.375, moderate: 1.55, active: 1.725, very_active: 1.9 };
const GOAL_DELTA = { lose_weight: -0.20, recomp: -0.10, maintain: 0, gain_muscle: 0.10, endurance: 0 };

const MET = {
  running: { low: 6, medium: 9, high: 11.5 },
  cycling: { low: 4, medium: 8, high: 12 },
  swimming: { low: 5.8, medium: 8, high: 10 },
  walking: { low: 2.8, medium: 3.8, high: 5 },
  strength: { low: 3, medium: 5, high: 6 },
  hiit: { low: 6, medium: 8, high: 10 },
  yoga: { low: 2.5, medium: 3, high: 4 },
  other: { low: 3, medium: 5, high: 7 }
};

function calorieBurn(type, intensity, weightKg, durationMin) {
  const t = MET[type] || MET.other;
  const m = t[intensity] || t.medium;
  return Math.round(m * (weightKg || 70) * (durationMin / 60));
}

function ageFromBirthdate(d) {
  if (!d) return null;
  const dt = new Date(d);
  return Math.floor((Date.now() - dt.getTime()) / (1000 * 60 * 60 * 24 * 365.25));
}

function todayISO() {
  return new Date().toISOString().substring(0, 10);
}

function nowISO() {
  return new Date().toISOString();
}

function startOfWeekISO() {
  const d = new Date();
  const day = (d.getUTCDay() + 6) % 7;
  d.setUTCDate(d.getUTCDate() - day);
  return d.toISOString().substring(0, 10);
}

function startOfMonthISO() {
  const d = new Date();
  return d.toISOString().substring(0, 7) + '-01';
}

function daysAgoISO(n) {
  const d = new Date();
  d.setUTCDate(d.getUTCDate() - n);
  return d.toISOString().substring(0, 10);
}

async function getProfile(userId) {
  const r = await pg('GET', '/fitness_profile?user_id=eq.' + encodeURIComponent(userId) + '&select=*');
  return (r && r[0]) || null;
}

function computeTargets(p) {
  if (!p.weight_kg_baseline || !p.height_cm || !p.birthdate || !p.sex) return null;
  const age = ageFromBirthdate(p.birthdate);
  const b = bmr(p.sex, p.weight_kg_baseline, p.height_cm, age);
  const tdee = b * (ACTIVITY_MULT[p.activity_level] || 1.55);
  const kcal = Math.round(tdee * (1 + (GOAL_DELTA[p.goal] || 0)));
  const proteinPerKg = p.goal === 'gain_muscle' ? 2.0 : (p.goal === 'lose_weight' ? 2.2 : 1.6);
  const protein = Math.round(p.weight_kg_baseline * proteinPerKg);
  const fat = Math.round(p.weight_kg_baseline * 0.9);
  const carbs = Math.max(0, Math.round((kcal - protein * 4 - fat * 9) / 4));
  const hydration = Math.round(p.weight_kg_baseline * 35);
  return { daily_kcal_target: kcal, protein_g_target: protein, carbs_g_target: carbs, fat_g_target: fat, hydration_ml_target: hydration };
}

let _userId = null;
async function resolveUserId() {
  if (input.user_id) return input.user_id;
  if (input.qualifiedUserId) return input.qualifiedUserId;
  try {
    const r = await pg('GET', '/user_profiles?select=user_id&limit=1');
    if (r && r[0] && r[0].user_id) return r[0].user_id;
  } catch (e) {}
  return 'default';
}
function getUserId() {
  return _userId || 'default';
}

function fmtNum(n, dp) {
  if (n == null || isNaN(n)) return '-';
  const m = Math.pow(10, dp || 0);
  return Math.round(n * m) / m;
}

async function offSearch(query, limit) {
  const url = OFF_SEARCH + '/search?q=' + encodeURIComponent(query) + '&page_size=' + (limit || 1) + '&fields=code,product_name,brands,nutriments,quantity,allergens_tags';
  try {
    const data = await helpers.httpRequest({ method: 'GET', url, headers: { 'User-Agent': UA }, timeout: 15000, json: true });
    return (data && (data.hits || data.products)) || [];
  } catch (e) {
    return [];
  }
}

async function offBarcode(code) {
  try {
    const url = OFF_BASE + '/api/v2/product/' + encodeURIComponent(code) + '.json?fields=code,product_name,brands,nutriments,quantity,allergens_tags';
    const data = await helpers.httpRequest({ method: 'GET', url, headers: { 'User-Agent': UA }, timeout: 15000, json: true });
    return data && data.product && data.status !== 0 ? data.product : null;
  } catch (e) {
    return null;
  }
}

function nutrientsFromOff(p, grams) {
  if (!p || !p.nutriments) return null;
  const n = p.nutriments;
  const factor = grams / 100;
  return {
    kcal: Math.round((n['energy-kcal_100g'] || 0) * factor),
    protein_g: Math.round((n.proteins_100g || 0) * factor * 10) / 10,
    carbs_g: Math.round((n.carbohydrates_100g || 0) * factor * 10) / 10,
    fat_g: Math.round((n.fat_100g || 0) * factor * 10) / 10,
    fiber_g: Math.round((n.fiber_100g || 0) * factor * 10) / 10
  };
}

async function llmEstimateNutrition(name, grams) {
  const schema = {
    type: 'object',
    additionalProperties: false,
    required: ['kcal_per_100g', 'protein_per_100g', 'carbs_per_100g', 'fat_per_100g', 'fiber_per_100g'],
    properties: {
      kcal_per_100g: { type: 'number' },
      protein_per_100g: { type: 'number' },
      carbs_per_100g: { type: 'number' },
      fat_per_100g: { type: 'number' },
      fiber_per_100g: { type: 'number' }
    }
  };
  try {
    const r = await llmJSON(
      'You estimate nutrition values per 100g for a single food item. Be conservative and realistic. Return numbers only.',
      'Food: ' + name,
      schema
    );
    const f = grams / 100;
    return {
      kcal: Math.round(r.kcal_per_100g * f),
      protein_g: Math.round(r.protein_per_100g * f * 10) / 10,
      carbs_g: Math.round(r.carbs_per_100g * f * 10) / 10,
      fat_g: Math.round(r.fat_per_100g * f * 10) / 10,
      fiber_g: Math.round(r.fiber_per_100g * f * 10) / 10
    };
  } catch (e) {
    return { kcal: 0, protein_g: 0, carbs_g: 0, fat_g: 0, fiber_g: 0 };
  }
}

async function resolveItemNutrition(name, grams) {
  if (name.match(/^[0-9]{8,14}$/)) {
    const p = await offBarcode(name);
    if (p) {
      const n = nutrientsFromOff(p, grams);
      if (n) return Object.assign({ source: 'off', off_id: p.code, confidence: 0.9, name: p.product_name || name }, n);
    }
  }
  const hits = await offSearch(name, 1);
  if (hits[0]) {
    const n = nutrientsFromOff(hits[0], grams);
    if (n && n.kcal > 0) return Object.assign({ source: 'off', off_id: hits[0].code, confidence: 0.7, name: hits[0].product_name || name }, n);
  }
  const llm = await llmEstimateNutrition(name, grams);
  return Object.assign({ source: 'llm', confidence: 0.5, name }, llm);
}

function sumItems(items) {
  const t = { kcal: 0, protein: 0, carbs: 0, fat: 0, fiber: 0 };
  for (const i of items) {
    t.kcal += i.kcal || 0;
    t.protein += i.protein_g || 0;
    t.carbs += i.carbs_g || 0;
    t.fat += i.fat_g || 0;
    t.fiber += i.fiber_g || 0;
  }
  return t;
}

function buddySays(s) {
  return s;
}

async function actionFitnessProfile(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'get').toLowerCase();
  if (sub === 'get') {
    const p = await getProfile(userId);
    if (!p) return buddySays('No profile yet. Run fitness_profile with sub_action=setup to create one.');
    let out = 'Buddy profile for you:\n';
    out += '  Sex: ' + (p.sex || '?') + ' | Birthdate: ' + (p.birthdate || '?') + ' (age ' + (ageFromBirthdate(p.birthdate) || '?') + ')\n';
    out += '  Height: ' + (p.height_cm || '?') + ' cm | Weight baseline: ' + (p.weight_kg_baseline || '?') + ' kg\n';
    out += '  Activity: ' + (p.activity_level || '?') + ' | Goal: ' + (p.goal || '?') + '\n';
    if (p.target_weight_kg) out += '  Target: ' + p.target_weight_kg + ' kg by ' + (p.target_date || 'open') + '\n';
    out += '  Daily targets: ' + (p.daily_kcal_target || '?') + ' kcal | P ' + (p.protein_g_target || '?') + 'g / C ' + (p.carbs_g_target || '?') + 'g / F ' + (p.fat_g_target || '?') + 'g | Water ' + (p.hydration_ml_target || '?') + ' ml\n';
    if (p.allergies && p.allergies.length) out += '  Allergies: ' + p.allergies.join(', ') + '\n';
    if (p.dietary_restrictions && p.dietary_restrictions.length) out += '  Diet: ' + p.dietary_restrictions.join(', ') + '\n';
    if (p.training_days_per_week) out += '  Training days/week: ' + p.training_days_per_week + '\n';
    return out.trim();
  }
  if (sub === 'setup' || sub === 'update') {
    const existing = await getProfile(userId);
    const patch = { user_id: userId };
    const fields = ['sex', 'birthdate', 'height_cm', 'weight_kg_baseline', 'activity_level', 'goal', 'target_weight_kg', 'target_date', 'training_days_per_week', 'preferred_workout_time', 'notes'];
    for (const f of fields) if (input[f] != null && input[f] !== '') patch[f] = input[f];
    if (input.allergies) patch.allergies = Array.isArray(input.allergies) ? input.allergies : String(input.allergies).split(',').map(s => s.trim()).filter(Boolean);
    if (input.dietary_restrictions) patch.dietary_restrictions = Array.isArray(input.dietary_restrictions) ? input.dietary_restrictions : String(input.dietary_restrictions).split(',').map(s => s.trim()).filter(Boolean);
    if (input.excluded_foods) patch.excluded_foods = Array.isArray(input.excluded_foods) ? input.excluded_foods : String(input.excluded_foods).split(',').map(s => s.trim()).filter(Boolean);
    const merged = Object.assign({}, existing || {}, patch);
    const targets = computeTargets(merged);
    if (targets) {
      if (input.daily_kcal_override) patch.daily_kcal_target = parseInt(input.daily_kcal_override);
      else if (!existing || !existing.daily_kcal_target || sub === 'setup') patch.daily_kcal_target = targets.daily_kcal_target;
      if (!existing || !existing.protein_g_target || sub === 'setup') {
        patch.protein_g_target = targets.protein_g_target;
        patch.carbs_g_target = targets.carbs_g_target;
        patch.fat_g_target = targets.fat_g_target;
      }
    }
    patch.updated_at = nowISO();
    let result;
    if (existing) {
      result = await pgPatch('/fitness_profile?user_id=eq.' + encodeURIComponent(userId), patch);
    } else {
      result = await pg('POST', '/fitness_profile', patch);
    }
    const saved = (result && result[0]) || patch;
    let out = (existing ? 'Profile updated.' : 'Profile created!') + ' Buddy is ready.\n';
    if (saved.daily_kcal_target) out += '  Daily target: ' + saved.daily_kcal_target + ' kcal (P ' + saved.protein_g_target + 'g / C ' + saved.carbs_g_target + 'g / F ' + saved.fat_g_target + 'g)\n';
    if (saved.hydration_ml_target) out += '  Water target: ' + saved.hydration_ml_target + ' ml\n';
    return out.trim();
  }
  return 'Unknown sub_action: ' + sub + '. Use setup, update, or get.';
}

async function actionLogMeal(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'from_text').toLowerCase();

  if (sub === 'delete') {
    const id = parseInt(input.meal_id);
    if (!id) return 'meal_id required.';
    await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/fitness_meals?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), headers: pgHeaders, timeout: 15000 });
    return 'Meal #' + id + ' deleted.';
  }
  if (sub === 'edit') {
    const id = parseInt(input.meal_id);
    if (!id) return 'meal_id required.';
    const patch = {};
    if (input.notes != null) patch.notes = input.notes;
    if (input.meal_type) patch.meal_type = input.meal_type;
    if (Object.keys(patch).length === 0) return 'Nothing to edit. Provide notes or meal_type.';
    await pgPatch('/fitness_meals?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), patch);
    return 'Meal #' + id + ' updated.';
  }
  if (sub === 'clear_day') {
    const date = input.date || todayISO();
    if (input.confirm !== true && input.confirm !== 'true') return 'Pass confirm=true to wipe all meals for ' + date + '.';
    await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/fitness_meals?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + date + 'T00:00:00&logged_at=lt.' + date + 'T23:59:59', headers: pgHeaders, timeout: 15000 });
    return 'All meals for ' + date + ' wiped.';
  }
  if (sub === 'from_memory') {
    const memId = parseInt(input.meal_memory_id);
    if (!memId) return 'meal_memory_id required.';
    const mem = await pg('GET', '/fitness_meal_memory?id=eq.' + memId + '&user_id=eq.' + encodeURIComponent(userId) + '&select=*');
    if (!mem || !mem[0]) return 'Meal memory not found.';
    const m = mem[0];
    const row = {
      user_id: userId,
      logged_at: input.logged_at || nowISO(),
      meal_type: input.meal_type || 'snack',
      items: m.items,
      total_kcal: m.total_kcal,
      total_protein_g: m.total_protein_g,
      total_carbs_g: m.total_carbs_g,
      total_fat_g: m.total_fat_g,
      total_fiber_g: m.total_fiber_g,
      input_source: 'memory',
      meal_memory_id: m.id,
      notes: input.notes || null
    };
    const saved = await pg('POST', '/fitness_meals', row);
    await pgPatch('/fitness_meal_memory?id=eq.' + memId, { times_logged: (m.times_logged || 0) + 1, last_logged_at: nowISO() });
    return 'Logged from memory: "' + m.name + '" - ' + Math.round(m.total_kcal) + ' kcal (P ' + fmtNum(m.total_protein_g, 1) + 'g / C ' + fmtNum(m.total_carbs_g, 1) + 'g / F ' + fmtNum(m.total_fat_g, 1) + 'g).';
  }

  let items = [];
  let inputSource = sub;
  let visionConfidence = null;
  let rawInput = input.raw_input || input.text || '';

  if (sub === 'from_text' || sub === 'from_voice') {
    const text = (input.text || input.raw_input || '').trim();
    if (!text) return 'Provide text or raw_input describing the meal (e.g. "100g oatmeal, 200ml milk, 1 banana").';
    inputSource = sub === 'from_voice' ? 'voice' : 'text';
    const schema = {
      type: 'object', additionalProperties: false,
      required: ['items'],
      properties: {
        items: { type: 'array', items: {
          type: 'object', additionalProperties: false,
          required: ['name', 'grams'],
          properties: { name: { type: 'string' }, grams: { type: 'number' } }
        } }
      }
    };
    try {
      const parsed = await llmJSON(
        'Extract food items and approximate weight in grams from a meal description. Convert units (1 banana ~120g, 1 slice bread ~30g, 1 egg ~50g, 1 cup rice cooked ~200g, 1 tbsp oil ~14g). Return strict JSON.',
        text,
        schema
      );
      items = parsed.items || [];
    } catch (e) {
      return 'Failed to parse meal description: ' + e.message;
    }
  } else if (sub === 'from_photo') {
    const fileRef = input.file_ref;
    if (!fileRef) return 'file_ref required for from_photo. The agent should pass the photo file_ref from the user message.';
    inputSource = 'photo';
    let img;
    try {
      img = await fetchFile(fileRef);
    } catch (e) {
      return 'Failed to fetch photo from File Bridge: ' + e.message;
    }
    const schema = {
      type: 'object', additionalProperties: false,
      required: ['items', 'overall_confidence'],
      properties: {
        items: { type: 'array', items: {
          type: 'object', additionalProperties: false,
          required: ['name', 'grams', 'confidence'],
          properties: { name: { type: 'string' }, grams: { type: 'number' }, confidence: { type: 'number' } }
        } },
        overall_confidence: { type: 'number' }
      }
    };
    try {
      const apiKey = await getOpenAIKey();
      const resp = await helpers.httpRequest({
        method: 'POST',
        url: 'https://api.openai.com/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
        body: {
          model: 'gpt-4o-mini',
          temperature: 0,
          response_format: { type: 'json_schema', json_schema: { name: 'meal', strict: true, schema } },
          messages: [{
            role: 'user',
            content: [
              { type: 'text', text: 'Identify each food item visible in this meal photo. For each, estimate the weight in grams as accurately as you can. Set confidence (0-1) per item and overall. Return strict JSON.' },
              { type: 'image_url', image_url: { url: 'data:' + img.mime + ';base64,' + img.base64 } }
            ]
          }]
        },
        json: true,
        timeout: 90000
      });
      const parsed = JSON.parse(resp.choices[0].message.content);
      items = parsed.items || [];
      visionConfidence = parsed.overall_confidence;
    } catch (e) {
      return 'Vision analysis failed: ' + e.message;
    }
  } else if (sub === 'from_barcode') {
    const code = (input.barcode || '').trim();
    const grams = parseFloat(input.grams) || 100;
    if (!code) return 'barcode required.';
    inputSource = 'barcode';
    items = [{ name: code, grams }];
  } else {
    return 'Unknown sub_action: ' + sub + '. Use from_text, from_voice, from_photo, from_barcode, from_memory, edit, delete, clear_day.';
  }

  if (!items.length) return 'No food items detected. Try again with more detail.';

  const enriched = [];
  for (const it of items) {
    const grams = it.grams || 100;
    const n = await resolveItemNutrition(it.name, grams);
    enriched.push({
      name: n.name,
      grams,
      kcal: n.kcal,
      protein_g: n.protein_g,
      carbs_g: n.carbs_g,
      fat_g: n.fat_g,
      fiber_g: n.fiber_g,
      source: n.source,
      confidence: it.confidence != null ? it.confidence : n.confidence,
      off_id: n.off_id || null
    });
  }

  const totals = sumItems(enriched);
  const row = {
    user_id: userId,
    logged_at: input.logged_at || nowISO(),
    meal_type: input.meal_type || 'snack',
    items: enriched,
    total_kcal: totals.kcal,
    total_protein_g: totals.protein,
    total_carbs_g: totals.carbs,
    total_fat_g: totals.fat,
    total_fiber_g: totals.fiber,
    input_source: inputSource,
    photo_ref: input.file_ref || null,
    raw_input: rawInput || null,
    vision_confidence: visionConfidence,
    notes: input.notes || null
  };
  const saved = await pg('POST', '/fitness_meals', row);
  const mealId = saved && saved[0] ? saved[0].id : null;

  let out = 'Logged ' + (row.meal_type || 'meal') + ' (#' + mealId + '):\n';
  for (const e of enriched) {
    out += '  - ' + e.name + ' ' + e.grams + 'g: ' + e.kcal + ' kcal (P ' + fmtNum(e.protein_g, 1) + 'g / C ' + fmtNum(e.carbs_g, 1) + 'g / F ' + fmtNum(e.fat_g, 1) + 'g)';
    out += ' [' + e.source + ', conf ' + Math.round((e.confidence || 0) * 100) + '%]\n';
  }
  out += 'Total: ' + Math.round(totals.kcal) + ' kcal | P ' + fmtNum(totals.protein, 1) + 'g | C ' + fmtNum(totals.carbs, 1) + 'g | F ' + fmtNum(totals.fat, 1) + 'g';
  if (visionConfidence != null) out += '\nOverall vision confidence: ' + Math.round(visionConfidence * 100) + '% - tell Buddy if amounts were off.';

  if (inputSource !== 'memory') {
    try {
      const sig = enriched.map(i => (i.name || '').toLowerCase().trim()).sort().join('|');
      const recent = await pg('GET', '/fitness_meals?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + daysAgoISO(14) + '&select=items,id&order=logged_at.desc');
      let count = 0;
      for (const r of (recent || [])) {
        const rsig = (r.items || []).map(i => (i.name || '').toLowerCase().trim()).sort().join('|');
        if (rsig === sig) count++;
      }
      if (count >= 3) out += '\n\nBuddy notes: you have logged this combination ' + count + 'x in 14 days. Want to save it as a meal memory? Reply "save as <name>".';
    } catch (e) {}
  }
  return out;
}

async function actionMealMemory(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'list').toLowerCase();
  if (sub === 'list') {
    const r = await pg('GET', '/fitness_meal_memory?user_id=eq.' + encodeURIComponent(userId) + '&select=id,name,total_kcal,total_protein_g,total_carbs_g,total_fat_g,times_logged,last_logged_at&order=times_logged.desc&limit=20');
    if (!r || !r.length) return 'No saved meals yet. After logging a meal, ask Buddy to "save as <name>".';
    let out = 'Your saved meals:\n';
    for (const m of r) out += '  #' + m.id + ' ' + m.name + ' - ' + Math.round(m.total_kcal) + ' kcal (P' + fmtNum(m.total_protein_g, 1) + '/C' + fmtNum(m.total_carbs_g, 1) + '/F' + fmtNum(m.total_fat_g, 1) + ') used ' + (m.times_logged || 0) + 'x\n';
    return out.trim();
  }
  if (sub === 'save') {
    const name = (input.name || '').trim();
    const fromMealId = parseInt(input.meal_id);
    if (!name) return 'name required.';
    let items, totals;
    if (fromMealId) {
      const meals = await pg('GET', '/fitness_meals?id=eq.' + fromMealId + '&user_id=eq.' + encodeURIComponent(userId) + '&select=*');
      if (!meals || !meals[0]) return 'Source meal not found.';
      items = meals[0].items;
      totals = { kcal: meals[0].total_kcal, protein: meals[0].total_protein_g, carbs: meals[0].total_carbs_g, fat: meals[0].total_fat_g, fiber: meals[0].total_fiber_g };
    } else {
      return 'Pass meal_id to save an existing meal as memory.';
    }
    const row = {
      user_id: userId, name,
      items, total_kcal: totals.kcal, total_protein_g: totals.protein, total_carbs_g: totals.carbs, total_fat_g: totals.fat, total_fiber_g: totals.fiber,
      times_logged: 1, last_logged_at: nowISO()
    };
    try {
      await pg('POST', '/fitness_meal_memory', row);
      return 'Saved as "' + name + '". Next time, just ask "log my ' + name + '".';
    } catch (e) {
      return 'Failed to save (maybe a meal with this name exists already?): ' + e.message;
    }
  }
  if (sub === 'delete') {
    const id = parseInt(input.meal_memory_id);
    if (!id) return 'meal_memory_id required.';
    await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/fitness_meal_memory?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), headers: pgHeaders, timeout: 15000 });
    return 'Meal memory #' + id + ' deleted.';
  }
  return 'Unknown sub_action: ' + sub;
}

async function actionSuggestMeal(input) {
  const userId = getUserId();
  const profile = await getProfile(userId);
  if (!profile) return 'Set up your profile first via fitness_profile.';
  const today = todayISO();
  const mealsToday = await pg('GET', '/fitness_meals?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + today + 'T00:00:00&select=total_kcal,total_protein_g,total_carbs_g,total_fat_g');
  let consumed = { kcal: 0, protein: 0, carbs: 0, fat: 0 };
  for (const m of (mealsToday || [])) {
    consumed.kcal += m.total_kcal || 0;
    consumed.protein += m.total_protein_g || 0;
    consumed.carbs += m.total_carbs_g || 0;
    consumed.fat += m.total_fat_g || 0;
  }
  const remaining = {
    kcal: (profile.daily_kcal_target || 2000) - consumed.kcal,
    protein: (profile.protein_g_target || 100) - consumed.protein,
    carbs: (profile.carbs_g_target || 200) - consumed.carbs,
    fat: (profile.fat_g_target || 60) - consumed.fat
  };
  const memHits = await pg('GET', '/fitness_meal_memory?user_id=eq.' + encodeURIComponent(userId) + '&select=name,total_kcal,total_protein_g,total_carbs_g,total_fat_g&order=times_logged.desc&limit=10');
  const allergies = (profile.allergies || []).join(', ');
  const restrictions = (profile.dietary_restrictions || []).join(', ');
  const memList = (memHits || []).map(m => m.name + ' (' + Math.round(m.total_kcal) + 'kcal, P' + fmtNum(m.total_protein_g, 0) + '/C' + fmtNum(m.total_carbs_g, 0) + '/F' + fmtNum(m.total_fat_g, 0) + ')').join('; ');
  const schema = {
    type: 'object', additionalProperties: false, required: ['suggestions'],
    properties: { suggestions: { type: 'array', items: {
      type: 'object', additionalProperties: false, required: ['name', 'why', 'kcal', 'protein_g', 'carbs_g', 'fat_g'],
      properties: { name: { type: 'string' }, why: { type: 'string' }, kcal: { type: 'number' }, protein_g: { type: 'number' }, carbs_g: { type: 'number' }, fat_g: { type: 'number' } }
    } } }
  };
  const userPrompt = 'Remaining today: ' + Math.round(remaining.kcal) + ' kcal, P ' + Math.round(remaining.protein) + 'g, C ' + Math.round(remaining.carbs) + 'g, F ' + Math.round(remaining.fat) + 'g.\n' +
    (allergies ? 'Allergies: ' + allergies + '\n' : '') +
    (restrictions ? 'Diet: ' + restrictions + '\n' : '') +
    (memList ? 'User favorites: ' + memList + '\n' : '') +
    'Suggest 3 realistic meal options that fit the remaining macros. Prefer favorites if a good fit. Each with name, one-sentence "why", and macro estimates.';
  try {
    const r = await llmJSON('You are Buddy, a personal nutrition coach. Be practical and motivating, never shaming.', userPrompt, schema);
    let out = 'Buddy suggests for your remaining ' + Math.round(remaining.kcal) + ' kcal:\n';
    for (let i = 0; i < r.suggestions.length; i++) {
      const s = r.suggestions[i];
      out += (i + 1) + '. ' + s.name + ' (~' + Math.round(s.kcal) + ' kcal | P' + Math.round(s.protein_g) + '/C' + Math.round(s.carbs_g) + '/F' + Math.round(s.fat_g) + ')\n   ' + s.why + '\n';
    }
    return out.trim();
  } catch (e) {
    return 'Failed to generate suggestions: ' + e.message;
  }
}

async function actionLogWorkout(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'log').toLowerCase();
  if (sub === 'delete') {
    const id = parseInt(input.workout_id);
    if (!id) return 'workout_id required.';
    await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/fitness_workouts?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), headers: pgHeaders, timeout: 15000 });
    return 'Workout #' + id + ' deleted.';
  }
  if (sub === 'edit') {
    const id = parseInt(input.workout_id);
    if (!id) return 'workout_id required.';
    const patch = {};
    for (const f of ['exercise_type', 'duration_min', 'intensity', 'distance_km', 'notes', 'perceived_exertion']) {
      if (input[f] != null && input[f] !== '') patch[f] = input[f];
    }
    if (Object.keys(patch).length === 0) return 'Nothing to edit.';
    await pgPatch('/fitness_workouts?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), patch);
    return 'Workout #' + id + ' updated.';
  }
  // log
  const profile = await getProfile(userId);
  let extracted = {
    exercise_type: input.exercise_type,
    duration_min: parseInt(input.duration_min) || null,
    intensity: input.intensity,
    distance_km: parseFloat(input.distance_km) || null,
    perceived_exertion: parseInt(input.perceived_exertion) || null
  };
  if (input.text || input.raw_input) {
    const text = input.text || input.raw_input;
    const schema = {
      type: 'object', additionalProperties: false,
      required: ['exercise_type', 'duration_min', 'intensity'],
      properties: {
        exercise_type: { type: 'string', enum: ['running', 'cycling', 'swimming', 'walking', 'strength', 'hiit', 'yoga', 'other'] },
        duration_min: { type: 'number' },
        intensity: { type: 'string', enum: ['low', 'medium', 'high'] },
        distance_km: { type: ['number', 'null'] },
        perceived_exertion: { type: ['number', 'null'] },
        notes: { type: ['string', 'null'] }
      }
    };
    try {
      const r = await llmJSON('Extract structured workout data from a user message (text or voice transcript). Map to one of: running, cycling, swimming, walking, strength, hiit, yoga, other. Intensity: low|medium|high. Return strict JSON.', text, schema);
      extracted = Object.assign(extracted, r);
    } catch (e) {
      // fallthrough; will validate below
    }
  }
  if (!extracted.exercise_type) return 'Could not determine exercise_type. Provide it explicitly or describe the workout (e.g. "30 min jog medium intensity").';
  if (!extracted.duration_min) return 'Could not determine duration_min.';
  const inten = extracted.intensity || 'medium';
  const weightKg = profile && profile.weight_kg_baseline ? profile.weight_kg_baseline : 70;
  const burned = calorieBurn(extracted.exercise_type, inten, weightKg, extracted.duration_min);
  const row = {
    user_id: userId,
    performed_at: input.performed_at || nowISO(),
    exercise_type: extracted.exercise_type,
    duration_min: extracted.duration_min,
    intensity: inten,
    distance_km: extracted.distance_km,
    sets: input.sets || null,
    calories_burned: burned,
    perceived_exertion: extracted.perceived_exertion,
    plan_session_id: input.plan_session_id ? parseInt(input.plan_session_id) : null,
    input_source: input.input_source || (input.text ? 'text' : 'manual'),
    raw_input: input.text || input.raw_input || null,
    notes: extracted.notes || input.notes || null
  };
  const saved = await pg('POST', '/fitness_workouts', row);
  const id = saved && saved[0] ? saved[0].id : null;
  // Auto-link to today's plan session if not provided
  if (!row.plan_session_id) {
    const sess = await pg('GET', '/fitness_plan_sessions?user_id=eq.' + encodeURIComponent(userId) + '&planned_for=eq.' + todayISO() + '&completed_at=is.null&select=id&limit=1');
    if (sess && sess[0]) {
      await pgPatch('/fitness_plan_sessions?id=eq.' + sess[0].id, { completed_at: nowISO(), workout_log_id: id });
      await pgPatch('/fitness_workouts?id=eq.' + id, { plan_session_id: sess[0].id });
    }
  }
  let out = 'Logged ' + extracted.exercise_type + ' ' + extracted.duration_min + ' min ' + inten + ' = ~' + burned + ' kcal burned (#' + id + ').';
  // Goal progress
  try {
    const goals = await pg('GET', '/fitness_goals?user_id=eq.' + encodeURIComponent(userId) + '&status=eq.active&goal_type=eq.workout_frequency&select=*');
    if (goals && goals[0]) {
      const g = goals[0];
      const since = startOfWeekISO();
      const wk = await pg('GET', '/fitness_workouts?user_id=eq.' + encodeURIComponent(userId) + '&performed_at=gte.' + since + 'T00:00:00&select=id');
      const cnt = (wk || []).length;
      out += '\nThis week: ' + cnt + '/' + g.target_value + ' workouts.';
      await pgPatch('/fitness_goals?id=eq.' + g.id, { current_value: cnt });
    }
  } catch (e) {}
  return out;
}

async function actionLogBody(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'log').toLowerCase();
  if (sub === 'log') {
    const row = { user_id: userId, measured_at: input.measured_at || nowISO() };
    for (const f of ['weight_kg', 'body_fat_pct', 'muscle_mass_kg', 'waist_cm', 'chest_cm', 'hip_cm', 'thigh_cm', 'arm_cm', 'photo_ref', 'notes']) {
      if (input[f] != null && input[f] !== '') row[f] = input[f];
    }
    if (!row.weight_kg && !row.body_fat_pct && !row.waist_cm) return 'Provide at least weight_kg, body_fat_pct, or one circumference.';
    const saved = await pg('POST', '/fitness_body', row);
    const id = saved && saved[0] ? saved[0].id : null;
    return 'Logged body data #' + id + ': ' + (row.weight_kg ? row.weight_kg + ' kg ' : '') + (row.body_fat_pct ? row.body_fat_pct + '% BF ' : '') + '(' + row.measured_at.substring(0, 10) + ').';
  }
  if (sub === 'list') {
    const days = parseInt(input.days) || 30;
    const since = daysAgoISO(days);
    const r = await pg('GET', '/fitness_body?user_id=eq.' + encodeURIComponent(userId) + '&measured_at=gte.' + since + 'T00:00:00&order=measured_at.desc&limit=50&select=*');
    if (!r || !r.length) return 'No body data in the last ' + days + ' days.';
    let out = 'Body log (last ' + days + ' days):\n';
    for (const e of r) out += '  ' + e.measured_at.substring(0, 10) + ': ' + (e.weight_kg ? e.weight_kg + 'kg ' : '') + (e.body_fat_pct ? e.body_fat_pct + '% BF ' : '') + (e.waist_cm ? 'Waist ' + e.waist_cm + 'cm ' : '') + '\n';
    return out.trim();
  }
  if (sub === 'trend') {
    const days = parseInt(input.days) || 30;
    const since = daysAgoISO(days);
    const r = await pg('GET', '/fitness_body?user_id=eq.' + encodeURIComponent(userId) + '&measured_at=gte.' + since + 'T00:00:00&order=measured_at.asc&select=measured_at,weight_kg,body_fat_pct');
    if (!r || r.length < 2) return 'Need at least 2 entries in last ' + days + ' days for a trend.';
    const first = r[0], last = r[r.length - 1];
    const dwt = (last.weight_kg && first.weight_kg) ? (last.weight_kg - first.weight_kg).toFixed(1) : null;
    const dbf = (last.body_fat_pct && first.body_fat_pct) ? (last.body_fat_pct - first.body_fat_pct).toFixed(1) : null;
    let out = 'Trend over ' + r.length + ' entries (' + first.measured_at.substring(0, 10) + ' to ' + last.measured_at.substring(0, 10) + '):\n';
    if (dwt) out += '  Weight: ' + first.weight_kg + ' to ' + last.weight_kg + ' kg (' + (dwt > 0 ? '+' : '') + dwt + ' kg)\n';
    if (dbf) out += '  Body fat: ' + first.body_fat_pct + ' to ' + last.body_fat_pct + '% (' + (dbf > 0 ? '+' : '') + dbf + '%)\n';
    return out.trim();
  }
  return 'Unknown sub_action: ' + sub;
}

async function actionLogHydration(input) {
