    for (const e of (t || [])) total += e.volume_ml;
    const profile = await getProfile(userId);
    const target = profile && profile.hydration_ml_target ? profile.hydration_ml_target : 2500;
    return 'Logged ' + ml + ' ml. Today: ' + total + ' / ' + target + ' ml (' + Math.round(total / target * 100) + '%).';
  }
  if (sub === 'today') {
    const t = await pg('GET', '/fitness_hydration?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + todayISO() + 'T00:00:00&select=volume_ml,beverage_type,logged_at&order=logged_at.asc');
    let total = 0;
    for (const e of (t || [])) total += e.volume_ml;
    const profile = await getProfile(userId);
    const target = profile && profile.hydration_ml_target ? profile.hydration_ml_target : 2500;
