async function actionGoals(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'list').toLowerCase();
  if (sub === 'list') {
    const r = await pg('GET', '/fitness_goals?user_id=eq.' + encodeURIComponent(userId) + '&status=eq.active&select=*&order=created_at.desc');
    if (!r || !r.length) return 'No active goals. Use sub_action=set to create one.';
    let out = 'Active goals:\n';
    for (const g of r) {
      const pct = g.target_value ? Math.round((g.current_value || 0) / g.target_value * 100) : 0;
      out += '  #' + g.id + ' ' + g.goal_type + ': ' + (g.current_value || 0) + ' / ' + g.target_value + ' ' + (g.target_unit || '') + ' (' + pct + '%)';
      if (g.deadline) out += ' by ' + g.deadline;
      out += '\n';
    }
    return out.trim();
  }
  if (sub === 'set') {
    const goalType = input.goal_type;
    const target = parseFloat(input.target_value);
    if (!goalType || !target) return 'goal_type and target_value required. goal_type: weight, body_fat, workout_frequency, distance, strength, habit, streak.';
    const row = {
      user_id: userId,
      goal_type: goalType,
      target_value: target,
      target_unit: input.target_unit || (goalType === 'weight' ? 'kg' : goalType === 'workout_frequency' ? 'workouts/week' : ''),
      current_value: parseFloat(input.current_value) || 0,
      deadline: input.deadline || null,
      status: 'active'
    };
    const saved = await pg('POST', '/fitness_goals', row);
    return 'Goal set: ' + goalType + ' = ' + target + ' ' + row.target_unit + (row.deadline ? ' by ' + row.deadline : '') + ' (#' + (saved && saved[0] ? saved[0].id : '?') + ').';
  }
  if (sub === 'archive') {
    const id = parseInt(input.goal_id);
    if (!id) return 'goal_id required.';
    await pgPatch('/fitness_goals?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), { status: input.status || 'achieved', achieved_at: nowISO() });
    return 'Goal #' + id + ' archived.';
  }
  return 'Unknown sub_action: ' + sub;
}

async function computeStreak(userId) {
  const r = await pg('GET', '/fitness_workouts?user_id=eq.' + encodeURIComponent(userId) + '&order=performed_at.desc&limit=60&select=performed_at');
  const r2 = await pg('GET', '/fitness_meals?user_id=eq.' + encodeURIComponent(userId) + '&order=logged_at.desc&limit=200&select=logged_at');
  const days = new Set();
  for (const e of (r || [])) days.add(e.performed_at.substring(0, 10));
  for (const e of (r2 || [])) days.add(e.logged_at.substring(0, 10));
  let streak = 0;
  let cursor = new Date();
  for (let i = 0; i < 60; i++) {
    const iso = cursor.toISOString().substring(0, 10);
    if (days.has(iso)) {
      streak++;
      cursor.setUTCDate(cursor.getUTCDate() - 1);
    } else {
      break;
    }
  }
  return streak;
}

async function actionSummary(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'today').toLowerCase();
  const profile = await getProfile(userId);
  let since;
  let label;
  if (sub === 'today') { since = todayISO(); label = 'Today (' + since + ')'; }
  else if (sub === 'week') { since = startOfWeekISO(); label = 'This week (since ' + since + ')'; }
  else if (sub === 'month') { since = startOfMonthISO(); label = 'This month (since ' + since + ')'; }
  else return 'Unknown sub_action: ' + sub;
  const meals = await pg('GET', '/fitness_meals?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + since + 'T00:00:00&select=total_kcal,total_protein_g,total_carbs_g,total_fat_g');
  const workouts = await pg('GET', '/fitness_workouts?user_id=eq.' + encodeURIComponent(userId) + '&performed_at=gte.' + since + 'T00:00:00&select=exercise_type,duration_min,calories_burned');
  const hydra = await pg('GET', '/fitness_hydration?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + since + 'T00:00:00&select=volume_ml');
  let kcal = 0, protein = 0, carbs = 0, fat = 0;
  for (const m of (meals || [])) { kcal += m.total_kcal || 0; protein += m.total_protein_g || 0; carbs += m.total_carbs_g || 0; fat += m.total_fat_g || 0; }
  let workoutMin = 0, burned = 0;
  for (const w of (workouts || [])) { workoutMin += w.duration_min || 0; burned += w.calories_burned || 0; }
  let water = 0;
  for (const h of (hydra || [])) water += h.volume_ml;
  const streak = await computeStreak(userId);
  let out = '*' + label + '*\n';
  if (profile && profile.daily_kcal_target) {
    const days = sub === 'today' ? 1 : (sub === 'week' ? 7 : 30);
    const target = profile.daily_kcal_target * days;
    out += 'Calories: ' + Math.round(kcal) + ' / ' + target + ' kcal (' + Math.round(kcal / target * 100) + '%)\n';
    out += 'Macros: P ' + fmtNum(protein, 0) + 'g / C ' + fmtNum(carbs, 0) + 'g / F ' + fmtNum(fat, 0) + 'g\n';
    if (sub === 'today') {
      const remain = target - kcal;
      out += 'Remaining: ' + Math.round(remain) + ' kcal (P ' + Math.max(0, Math.round((profile.protein_g_target || 0) - protein)) + 'g / C ' + Math.max(0, Math.round((profile.carbs_g_target || 0) - carbs)) + 'g / F ' + Math.max(0, Math.round((profile.fat_g_target || 0) - fat)) + 'g)\n';
    }
  } else {
    out += 'Calories: ' + Math.round(kcal) + ' kcal | P ' + fmtNum(protein, 0) + 'g / C ' + fmtNum(carbs, 0) + 'g / F ' + fmtNum(fat, 0) + 'g\n';
  }
  out += 'Workouts: ' + (workouts || []).length + ' (' + workoutMin + ' min, ~' + burned + ' kcal burned)\n';
  if (profile && profile.hydration_ml_target) {
    const days = sub === 'today' ? 1 : (sub === 'week' ? 7 : 30);
    out += 'Water: ' + water + ' / ' + (profile.hydration_ml_target * days) + ' ml\n';
  } else {
    out += 'Water: ' + water + ' ml\n';
  }
  out += 'Active streak: ' + streak + ' day(s)';
  if (streak >= 7) out += ' - on fire!';
  return out;
}

async function actionTrainingPlan(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'today').toLowerCase();
  if (sub === 'get_active' || sub === 'today') {
    const plans = await pg('GET', '/fitness_plans?user_id=eq.' + encodeURIComponent(userId) + '&status=eq.active&select=*&order=start_date.desc&limit=1');
    if (!plans || !plans[0]) return 'No active training plan. Use sub_action=generate_custom or import_template to create one.';
    const plan = plans[0];
    if (sub === 'today') {
      const today = todayISO();
      const sess = await pg('GET', '/fitness_plan_sessions?plan_id=eq.' + plan.id + '&planned_for=eq.' + today + '&select=*');
      if (!sess || !sess[0]) return 'No training session planned for today on plan "' + plan.name + '".';
      const s = sess[0];
      let out = 'Today on "' + plan.name + '" (Week ' + s.week_num + ', Day ' + s.day_num + '): ' + (s.name || 'Workout') + '\n';
      const exs = Array.isArray(s.exercises) ? s.exercises : [];
      for (const e of exs) out += '  - ' + (e.name || 'Exercise') + ': ' + (e.sets || 3) + 'x' + (e.reps || 10) + (e.weight_kg ? ' @ ' + e.weight_kg + 'kg' : '') + (e.rest_s ? ' (rest ' + e.rest_s + 's)' : '') + '\n';
      out += s.completed_at ? 'Status: completed' : 'Status: open - log your workout to mark complete';
      return out;
    }
    let out = 'Active plan: "' + plan.name + '" (' + plan.methodology + ')\n';
    out += '  Week ' + plan.current_week + ' / ' + plan.weeks_total + ' | ' + plan.start_date + ' to ' + plan.end_date + '\n';
    return out;
  }
  if (sub === 'generate_custom') {
    const profile = await getProfile(userId);
    if (!profile) return 'Set up your profile first.';
    const goal = input.goal || profile.goal || 'gain_muscle';
    const weeks = parseInt(input.weeks) || 4;
    const daysPerWeek = parseInt(input.days_per_week) || profile.training_days_per_week || 3;
    const equipment = input.equipment || 'gym';

    let exerciseDb = [];
    try {
      const wgerData = await helpers.httpRequest({ method: 'GET', url: WGER_BASE + '/exerciseinfo/?language=2&limit=80', headers: { 'User-Agent': UA }, json: true, timeout: 20000 });
      for (const e of ((wgerData && wgerData.results) || [])) {
        const tr = (e.translations || []).find(t => t.language === 2) || (e.translations || [])[0];
        if (!tr) continue;
        exerciseDb.push({
          id: e.id,
          name: tr.name,
          category: e.category && e.category.name,
          muscles: (e.muscles || []).map(m => m.name_en || m.name),
          equipment: (e.equipment || []).map(eq => eq.name)
        });
      }
    } catch (err) {
      // continue with empty db
    }
    const dbStr = exerciseDb.slice(0, 60).map(e => '#' + e.id + ' ' + e.name + ' [' + e.category + '|' + e.equipment.join(',') + '|' + e.muscles.join(',') + ']').join('\n');

    const schema = {
      type: 'object', additionalProperties: false,
      required: ['name', 'methodology', 'sessions'],
      properties: {
        name: { type: 'string' },
        methodology: { type: 'string', enum: ['linear', 'undulating', 'periodized'] },
        sessions: {
          type: 'array',
          items: {
            type: 'object', additionalProperties: false,
            required: ['week_num', 'day_num', 'name', 'is_deload', 'exercises'],
            properties: {
              week_num: { type: 'number' },
              day_num: { type: 'number' },
              name: { type: 'string' },
              is_deload: { type: 'boolean' },
              exercises: {
                type: 'array',
                items: {
                  type: 'object', additionalProperties: false,
                  required: ['name', 'sets', 'reps'],
                  properties: {
                    wger_id: { type: ['number', 'null'] },
                    name: { type: 'string' },
                    sets: { type: 'number' },
                    reps: { type: 'string' },
                    weight_kg: { type: ['number', 'null'] },
                    rest_s: { type: ['number', 'null'] },
                    notes: { type: ['string', 'null'] }
                  }
                }
              }
            }
          }
        }
      }
    };
    const sys = 'You are Buddy, an evidence-based personal trainer. Generate a training plan as strict JSON. Use exercises from the wger database (provide wger_id when possible). Apply progressive overload across weeks and a deload in the last week if weeks >= 4.';
    const user = 'Profile: ' + (profile.sex || '?') + ', age ' + (ageFromBirthdate(profile.birthdate) || '?') + ', ' + (profile.weight_kg_baseline || '?') + ' kg, ' + (profile.height_cm || '?') + ' cm, activity: ' + (profile.activity_level || 'moderate') + '.\n' +
      'Goal: ' + goal + '. Duration: ' + weeks + ' weeks, ' + daysPerWeek + ' sessions per week. Equipment available: ' + equipment + '.\n' +
      'Available wger exercises (use wger_id when matching):\n' + (dbStr || '(database unavailable, choose your own)') + '\n' +
      'Return ' + (weeks * daysPerWeek) + ' sessions total. Use 4-6 exercises per session. Mark week ' + weeks + ' as deload if weeks >= 4.';
    let plan;
    try {
      plan = await llmJSON(sys, user, schema);
    } catch (e) {
      return 'Plan generation failed: ' + e.message;
    }
    const start = todayISO();
    const endDate = new Date();
    endDate.setUTCDate(endDate.getUTCDate() + weeks * 7);
    const endStr = endDate.toISOString().substring(0, 10);
    // Deactivate any existing active plan
    await pgPatch('/fitness_plans?user_id=eq.' + encodeURIComponent(userId) + '&status=eq.active', { status: 'paused' });
    const planRow = {
      user_id: userId,
      name: plan.name,
      goal_type: goal,
      methodology: plan.methodology,
      start_date: start,
      end_date: endStr,
      weeks_total: weeks,
      current_week: 1,
      status: 'active',
      structure: { sessions_count: plan.sessions.length, days_per_week: daysPerWeek }
    };
    const savedPlan = await pg('POST', '/fitness_plans', planRow);
    const planId = savedPlan && savedPlan[0] ? savedPlan[0].id : null;
    if (!planId) return 'Plan saved partially - could not get plan ID.';
    const sessionRows = [];
    for (const s of plan.sessions) {
      const offsetDays = (s.week_num - 1) * 7 + (s.day_num - 1);
      const planned = new Date(start);
      planned.setUTCDate(planned.getUTCDate() + offsetDays);
      sessionRows.push({
        plan_id: planId,
        user_id: userId,
        week_num: s.week_num,
        day_num: s.day_num,
        name: s.name,
        exercises: s.exercises,
        planned_for: planned.toISOString().substring(0, 10),
        completion_notes: s.is_deload ? 'deload' : null
      });
    }
    if (sessionRows.length) await pg('POST', '/fitness_plan_sessions', sessionRows);
    let out = 'Plan "' + plan.name + '" created!\n';
    out += '  Methodology: ' + plan.methodology + ' | ' + weeks + ' weeks | ' + daysPerWeek + 'x/week\n';
    out += '  ' + plan.sessions.length + ' sessions scheduled (' + start + ' to ' + endStr + ')\n';
    out += '  First session: ' + (plan.sessions[0] ? plan.sessions[0].name : '?') + ' tomorrow';
    return out;
  }
  if (sub === 'import_template') {
    const tplId = parseInt(input.template_id);
    if (!tplId) return 'template_id required (from wger-exercises list_public_templates).';
    let tpl;
    try {
      tpl = await helpers.httpRequest({ method: 'GET', url: WGER_BASE + '/public-templates/' + tplId + '/', headers: { 'User-Agent': UA }, json: true, timeout: 20000 });
    } catch (e) {
      return 'Failed to fetch wger template: ' + e.message;
    }
    if (!tpl || !tpl.id) return 'Template ' + tplId + ' not found on wger.';
    const start = todayISO();
    const days = Array.isArray(tpl.days) ? tpl.days.filter(d => !d.is_rest) : [];
    const weeks = parseInt(input.weeks) || 4;
    const endDate = new Date();
    endDate.setUTCDate(endDate.getUTCDate() + weeks * 7);
    await pgPatch('/fitness_plans?user_id=eq.' + encodeURIComponent(userId) + '&status=eq.active', { status: 'paused' });
    const planRow = {
      user_id: userId,
      name: tpl.name || ('wger template #' + tplId),
      goal_type: input.goal || 'gain_muscle',
      methodology: 'linear',
      start_date: start,
      end_date: endDate.toISOString().substring(0, 10),
      weeks_total: weeks,
      current_week: 1,
      status: 'active',
      structure: { source: 'wger', template_id: tplId }
    };
    const savedPlan = await pg('POST', '/fitness_plans', planRow);
    const planId = savedPlan && savedPlan[0] ? savedPlan[0].id : null;
    if (!planId) return 'Plan saved partially.';
    const sessionRows = [];
    for (let w = 1; w <= weeks; w++) {
      for (let i = 0; i < days.length; i++) {
        const d = days[i];
        const slots = Array.isArray(d.slots) ? d.slots : [];
        const exercises = slots.map(s => {
          const cfg = (s.config && s.config[0]) || {};
          return {
            wger_id: s.exercise || (s.exercises && s.exercises[0]) || null,
            name: s.name || ('Exercise #' + (s.exercise || '?')),
            sets: parseInt(cfg.sets) || 3,
            reps: cfg.reps || '8-12',
            weight_kg: parseFloat(cfg.weight) || null,
            rest_s: parseInt(cfg.rest) || null
          };
        });
        const offsetDays = (w - 1) * 7 + i;
        const planned = new Date(start);
        planned.setUTCDate(planned.getUTCDate() + offsetDays);
        sessionRows.push({
          plan_id: planId,
          user_id: userId,
          week_num: w,
          day_num: i + 1,
          name: d.description || ('Day ' + (i + 1)),
          exercises,
          planned_for: planned.toISOString().substring(0, 10)
        });
      }
    }
    if (sessionRows.length) await pg('POST', '/fitness_plan_sessions', sessionRows);
    return 'Imported wger template "' + planRow.name + '" as your active plan: ' + sessionRows.length + ' sessions over ' + weeks + ' weeks.';
  }
  if (sub === 'list_templates') {
    try {
      const tpls = await helpers.httpRequest({ method: 'GET', url: WGER_BASE + '/public-templates/?limit=20', headers: { 'User-Agent': UA }, json: true, timeout: 20000 });
      const items = (tpls && tpls.results) || [];
      if (!items.length) return 'No public wger templates available.';
      let out = 'Available wger public templates:\n';
      for (const t of items) out += '  #' + t.id + ' ' + (t.name || 'Untitled') + '\n';
      return out.trim();
    } catch (e) {
      return 'Failed to fetch templates: ' + e.message;
    }
  }
  if (sub === 'complete_session') {
    const id = parseInt(input.session_id);
    if (!id) return 'session_id required.';
    await pgPatch('/fitness_plan_sessions?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), { completed_at: nowISO(), completion_notes: input.notes || null });
    return 'Session #' + id + ' marked complete.';
  }
  if (sub === 'adjust') {
    const planId = parseInt(input.plan_id);
    if (!planId) {
      const plans = await pg('GET', '/fitness_plans?user_id=eq.' + encodeURIComponent(userId) + '&status=eq.active&select=id&limit=1');
      if (!plans || !plans[0]) return 'No active plan to adjust.';
    }
    const note = input.adjustment_note || 'manual adjustment';
    return 'Plan adjustment requested: ' + note + '. (V1: noted in plan.notes; deeper restructure is V2.)';
  }
  return 'Unknown sub_action: ' + sub;
}

async function actionReminders(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'list').toLowerCase();
  const chatId = input.chatId || input.chat_id;
  if (sub === 'setup') {
    const presetName = input.preset || 'all';
    if (!chatId) return 'chat_id required (passed by the agent).';
    const presets = {
      morning_meal: { instruction: 'Buddy: gentle reminder to log breakfast if not logged yet.', schedule: 'daily', time: '08:00', notify_mode: 'on_change' },
      evening_summary: { instruction: 'Buddy: send today\'s fitness summary.', schedule: 'daily', time: '21:00', notify_mode: 'always' },
      weekly_report: { instruction: 'Buddy: send the weekly fitness report with insights.', schedule: 'weekly', day: 'sun', time: '19:00', notify_mode: 'always' }
    };
    const wanted = presetName === 'all' ? Object.keys(presets) : [presetName];
    const created = [];
    for (const k of wanted) {
      const p = presets[k];
      if (!p) continue;
      const row = {
        user_id: userId,
        chat_id: String(chatId),
        instruction: p.instruction,
        schedule: { type: p.schedule, time: p.time, day: p.day },
        timezone: input.timezone || 'Europe/Berlin',
        enabled: true,
        notify_mode: p.notify_mode,
        next_run: null
      };
      try {
        await pg('POST', '/scheduled_actions', row);
        created.push(k);
      } catch (e) {
        // continue
      }
    }
    return 'Reminders set up: ' + created.join(', ') + '. Heartbeat will fire them on schedule.';
  }
  if (sub === 'list') {
    const r = await pg('GET', '/scheduled_actions?user_id=eq.' + encodeURIComponent(userId) + '&instruction=ilike.Buddy:*&select=id,instruction,schedule,enabled,notify_mode,next_run&order=id.asc');
    if (!r || !r.length) return 'No Buddy reminders set up yet. Use sub_action=setup with preset=morning_meal|evening_summary|weekly_report|all.';
    let out = 'Your Buddy reminders:\n';
    for (const a of r) out += '  #' + a.id + ' ' + (a.enabled ? '[on]' : '[off]') + ' ' + JSON.stringify(a.schedule) + ' - ' + a.instruction.substring(0, 80) + '\n';
    return out.trim();
  }
  if (sub === 'disable') {
    const id = parseInt(input.reminder_id);
    if (!id) return 'reminder_id required.';
    await pgPatch('/scheduled_actions?id=eq.' + id + '&user_id=eq.' + encodeURIComponent(userId), { enabled: false });
    return 'Reminder #' + id + ' disabled.';
  }
  return 'Unknown sub_action: ' + sub;
}

async function actionInsights(input) {
  const userId = getUserId();
  const sub = (input.sub_action || 'list').toLowerCase();
  if (sub === 'list') {
    const r = await pg('GET', "/memory_long?category=eq.insight&entity_name=eq.fitness&select=content,importance,created_at&order=created_at.desc&limit=10");
    if (!r || !r.length) return 'No insights yet. Run sub_action=analyze (after at least 14 days of logs).';
    let out = 'Buddy insights:\n';
    for (const i of r) out += '  [' + i.created_at.substring(0, 10) + ' imp ' + i.importance + '] ' + i.content + '\n';
    return out.trim();
  }
  if (sub === 'analyze') {
    const since = daysAgoISO(30);
    const meals = await pg('GET', '/fitness_meals?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + since + 'T00:00:00&select=logged_at,meal_type,total_kcal,total_protein_g,total_carbs_g,total_fat_g');
    const workouts = await pg('GET', '/fitness_workouts?user_id=eq.' + encodeURIComponent(userId) + '&performed_at=gte.' + since + 'T00:00:00&select=performed_at,exercise_type,duration_min,intensity');
    const body = await pg('GET', '/fitness_body?user_id=eq.' + encodeURIComponent(userId) + '&measured_at=gte.' + since + 'T00:00:00&select=measured_at,weight_kg,body_fat_pct');
    if ((meals || []).length < 14) return 'Need at least 14 meal logs for meaningful insights. You have ' + (meals || []).length + '.';
    const stats = {
      meal_count: (meals || []).length,
      workout_count: (workouts || []).length,
      avg_kcal_per_day: 0,
      weekday_carbs: 0,
      weekend_carbs: 0
    };
    let weekdayMeals = 0, weekendMeals = 0;
    for (const m of (meals || [])) {
      stats.avg_kcal_per_day += m.total_kcal || 0;
      const wd = new Date(m.logged_at).getUTCDay();
      if (wd === 0 || wd === 6) { stats.weekend_carbs += m.total_carbs_g || 0; weekendMeals++; }
      else { stats.weekday_carbs += m.total_carbs_g || 0; weekdayMeals++; }
    }
    const days = Math.max(1, Math.ceil((Date.now() - new Date(since).getTime()) / 86400000));
    stats.avg_kcal_per_day = Math.round(stats.avg_kcal_per_day / days);
    stats.weekday_carbs_per_meal = weekdayMeals ? Math.round(stats.weekday_carbs / weekdayMeals) : 0;
    stats.weekend_carbs_per_meal = weekendMeals ? Math.round(stats.weekend_carbs / weekendMeals) : 0;
    const schema = {
      type: 'object', additionalProperties: false, required: ['insights'],
      properties: { insights: { type: 'array', items: {
        type: 'object', additionalProperties: false,
        required: ['content', 'importance'],
        properties: { content: { type: 'string' }, importance: { type: 'number' } }
      } } }
    };
    const sys = 'You are Buddy, evidence-based personal trainer. Look at user fitness stats and surface 3-5 actionable patterns. Each insight: 1 sentence, importance 1-10. No shaming, motivating tone.';
    const user = 'Stats over last ' + days + ' days:\n' + JSON.stringify(stats, null, 2) + '\nWorkouts: ' + JSON.stringify((workouts || []).slice(0, 20).map(w => ({ d: w.performed_at.substring(0, 10), t: w.exercise_type, m: w.duration_min, i: w.intensity })));
    let r;
    try {
      r = await llmJSON(sys, user, schema);
    } catch (e) {
      return 'Insight generation failed: ' + e.message;
    }
    const created = [];
    for (const i of r.insights) {
      const row = {
        content: i.content,
        category: 'insight',
        entity_name: 'fitness',
        importance: Math.max(1, Math.min(10, Math.round(i.importance))),
        tags: ['fitness', 'pattern'],
        metadata: { domain: 'fitness', user_id: userId, generated_at: nowISO() }
      };
      try {
        await pg('POST', '/memory_long', row);
        created.push(i.content);
      } catch (e) {}
    }
    let out = 'Generated ' + created.length + ' insights:\n';
    for (const c of created) out += '  - ' + c + '\n';
    return out.trim();
  }
  return 'Unknown sub_action: ' + sub;
}

async function actionExport(input) {
  const userId = getUserId();
  const type = input.type || 'meals';
  const since = input.since || daysAgoISO(30);
  const until = input.until || todayISO();
  let rows = [];
  let header = '';
  if (type === 'meals') {
    rows = await pg('GET', '/fitness_meals?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + since + 'T00:00:00&logged_at=lte.' + until + 'T23:59:59&order=logged_at.asc&select=logged_at,meal_type,total_kcal,total_protein_g,total_carbs_g,total_fat_g,total_fiber_g,input_source,notes');
    header = 'logged_at,meal_type,kcal,protein_g,carbs_g,fat_g,fiber_g,source,notes';
  } else if (type === 'workouts') {
    rows = await pg('GET', '/fitness_workouts?user_id=eq.' + encodeURIComponent(userId) + '&performed_at=gte.' + since + 'T00:00:00&performed_at=lte.' + until + 'T23:59:59&order=performed_at.asc&select=performed_at,exercise_type,duration_min,intensity,distance_km,calories_burned,perceived_exertion,notes');
    header = 'performed_at,exercise_type,duration_min,intensity,distance_km,calories_burned,rpe,notes';
  } else if (type === 'body') {
    rows = await pg('GET', '/fitness_body?user_id=eq.' + encodeURIComponent(userId) + '&measured_at=gte.' + since + 'T00:00:00&measured_at=lte.' + until + 'T23:59:59&order=measured_at.asc&select=measured_at,weight_kg,body_fat_pct,muscle_mass_kg,waist_cm,chest_cm,hip_cm,thigh_cm,arm_cm,notes');
    header = 'measured_at,weight_kg,body_fat_pct,muscle_mass_kg,waist_cm,chest_cm,hip_cm,thigh_cm,arm_cm,notes';
  } else if (type === 'hydration') {
    rows = await pg('GET', '/fitness_hydration?user_id=eq.' + encodeURIComponent(userId) + '&logged_at=gte.' + since + 'T00:00:00&logged_at=lte.' + until + 'T23:59:59&order=logged_at.asc&select=logged_at,volume_ml,beverage_type');
    header = 'logged_at,volume_ml,beverage_type';
  } else {
    return 'Unknown type: ' + type + '. Use meals, workouts, body, hydration.';
  }
  const lines = [header];
  for (const r of (rows || [])) {
    const cols = header.split(',').map(k => {
      const colMap = { kcal: 'total_kcal', protein_g: 'total_protein_g', carbs_g: 'total_carbs_g', fat_g: 'total_fat_g', fiber_g: 'total_fiber_g', source: 'input_source', rpe: 'perceived_exertion' };
      const key = colMap[k] || k;
      const v = r[key];
      if (v == null) return '';
      const s = String(v).replace(/"/g, '""');
      return /[,"\n]/.test(s) ? '"' + s + '"' : s;
    });
    lines.push(cols.join(','));
  }
  const csv = lines.join('\n');
  // Upload to File Bridge so it can be sent as a Telegram document
  try {
    const fname = 'fitness-' + type + '-' + since + '-to-' + until + '.csv';
    const upload = await helpers.httpRequest({
      method: 'POST',
      url: FILE_BRIDGE + '/upload/base64',
      headers: { 'Content-Type': 'application/json' },
      body: { content_base64: Buffer.from(csv).toString('base64'), file_name: fname, mime_type: 'text/csv' },
      json: true,
      timeout: 30000
    });
    return 'CSV exported: ' + (rows || []).length + ' rows. file_ref: ' + (upload && upload.id) + ' (filename: ' + fname + ')';
  } catch (e) {
    if (csv.length > 4000) return 'CSV ready (' + (rows || []).length + ' rows) but File Bridge upload failed and inline send is too large. Run on a smaller date range or check File Bridge.';
    return 'CSV (' + (rows || []).length + ' rows):\n' + csv;
  }
}

async function actionNutritionLookup(input) {
  const sub = (input.sub_action || 'by_name').toLowerCase();
  if (sub === 'by_barcode') {
    const code = (input.barcode || '').trim();
    if (!code) return 'barcode required.';
    const p = await offBarcode(code);
    if (!p) return 'Product ' + code + ' not found in OpenFoodFacts.';
    const n = p.nutriments || {};
    let out = (p.product_name || 'Unknown') + (p.brands ? ' (' + p.brands + ')' : '') + (p.quantity ? ' - ' + p.quantity : '') + '\n';
    out += '  Per 100g: ' + (n['energy-kcal_100g'] || '?') + ' kcal | P ' + (n.proteins_100g || '?') + 'g | C ' + (n.carbohydrates_100g || '?') + 'g | F ' + (n.fat_100g || '?') + 'g\n';
    if (p.allergens_tags && p.allergens_tags.length) out += '  Allergens: ' + p.allergens_tags.map(a => a.replace('en:', '')).join(', ') + '\n';
    return out.trim();
  }
  if (sub === 'by_name') {
    const q = (input.query || '').trim();
    if (!q) return 'query required.';
    const limit = Math.min(Math.max(parseInt(input.limit) || 5, 1), 10);
    const hits = await offSearch(q, limit);
    if (!hits.length) return 'No products found for "' + q + '".';
    let out = 'OpenFoodFacts results for "' + q + '":\n';
    for (let i = 0; i < hits.length; i++) {
      const p = hits[i];
      const n = p.nutriments || {};
      out += (i + 1) + '. ' + (p.product_name || 'Unknown') + (p.brands ? ' (' + p.brands + ')' : '');
      if (p.code) out += ' [#' + p.code + ']';
      out += '\n   Per 100g: ' + (n['energy-kcal_100g'] || '?') + ' kcal | P ' + (n.proteins_100g || '?') + 'g | C ' + (n.carbohydrates_100g || '?') + 'g | F ' + (n.fat_100g || '?') + 'g\n';
    }
    return out.trim();
  }
  return 'Unknown sub_action: ' + sub;
}

try {
  _userId = await resolveUserId();
  let result;
  if (action === 'fitness_profile') result = await actionFitnessProfile(input);
  else if (action === 'log_meal') result = await actionLogMeal(input);
  else if (action === 'meal_memory') result = await actionMealMemory(input);
  else if (action === 'suggest_meal') result = await actionSuggestMeal(input);
  else if (action === 'log_workout') result = await actionLogWorkout(input);
  else if (action === 'log_body') result = await actionLogBody(input);
  else if (action === 'log_hydration') result = await actionLogHydration(input);
  else if (action === 'goals') result = await actionGoals(input);
  else if (action === 'summary') result = await actionSummary(input);
  else if (action === 'training_plan') result = await actionTrainingPlan(input);
  else if (action === 'reminders') result = await actionReminders(input);
  else if (action === 'insights') result = await actionInsights(input);
  else if (action === 'export') result = await actionExport(input);
  else if (action === 'nutrition_lookup') result = await actionNutritionLookup(input);
  else result = 'Unknown action: ' + action + '. Available: fitness_profile, log_meal, meal_memory, suggest_meal, log_workout, log_body, log_hydration, goals, summary, training_plan, reminders, insights, export, nutrition_lookup.';
  let text = typeof result === 'string' ? result : JSON.stringify(result);
  if (text.length > 5000) text = text.substring(0, 5000) + '\n... (truncated, ' + text.length + ' chars total)';
  return [{ json: { result: text } }];
} catch (err) {
  return [{ json: { error: 'Buddy error: ' + (err.message || String(err)) } }];
}
